import React, { useState } from "react";

/**
 * Props:
 * - favorites: string[]           // ["Atlanta, US", "New York, US", ...]
 * - onSearch: (q: string) => void
 * - onSelectFavorite: (city: string) => void
 * - onAddFavorite?: (city: string) => void
 */
export default function SearchSection({
  favorites = [],
  onSearch,
  onSelectFavorite,
  onAddFavorite,
}) {
  const [q, setQ] = useState("");

  const submit = (e) => {
    e?.preventDefault?.();
    const trimmed = q.trim();
    if (!trimmed) return;
    onSearch?.(trimmed);
    onAddFavorite?.(trimmed);
    setQ("");
  };

  return (
    <section className="w-full rounded-2xl overflow-hidden shadow-xl border border-white/10 bg-black/50 backdrop-blur-md">
      <div className="p-3 text-white/90 text-base font-semibold bg-black/40 border-b border-white/10">
        Search & Favorites
      </div>

      <div className="p-4 space-y-4">
        {/* Search bar */}
        <form onSubmit={submit} className="flex items-center gap-2">
          <input
            value={q}
            onChange={(e) => setQ(e.target.value)}
            placeholder="Search city (e.g., Atlanta, US)"
            className="flex-1 px-4 py-3 rounded-xl bg-black/40 border border-white/10 text-white placeholder-white/50 outline-none focus:border-purple-400/50"
          />
          <button
            type="submit"
            className="px-4 py-3 rounded-xl bg-purple-600/70 hover:bg-purple-600 text-white font-semibold shadow"
          >
            Search
          </button>
        </form>

        {/* Favorites chips */}
        <div className="flex flex-wrap gap-2">
          {favorites.length ? (
            favorites.map((city) => (
              <button
                key={city}
                onClick={() => onSelectFavorite?.(city)}
                className="px-3 py-2 rounded-xl bg-black/40 border border-white/10 text-white/90 hover:text-white hover:bg-white/10"
              >
                {city}
              </button>
            ))
          ) : (
            <div className="text-white/60 text-sm">No favorites yet.</div>
          )}
        </div>
      </div>
    </section>
  );
}
